#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
    struct Node* prev;
} Node;

Node* createNode(int data) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = data;
    n->next = NULL;
    n->prev = NULL;
    return n;
}

Node* deleteAll(Node* head, int X) {
    Node* cur = head;
    while (cur) {
        Node* nxt = cur->next;
        if (cur->data == X) {
            if (cur == head) {
                head = cur->next;
                if (head) head->prev = NULL;
            } else {
                cur->prev->next = cur->next;
                if (cur->next) cur->next->prev = cur->prev;
            }
            free(cur);
        }
        cur = nxt;
    }
    return head;
}

void printList(Node* head) {
    if (!head) { printf("-1\n"); return; }
    Node* p = head;
    while (p) {
        printf("%d", p->data);
        if (p->next) printf(" ");
        p = p->next;
    }
    printf("\n");
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node* head = NULL; Node* tail = NULL;
        for (int i = 0; i < N; ++i) {
            int val; scanf("%d", &val);
            Node* nd = createNode(val);
            if (!head) { head = tail = nd; }
            else { tail->next = nd; nd->prev = tail; tail = nd; }
        }
        int X; scanf("%d", &X);
        head = deleteAll(head, X);
        printList(head);
        // free remaining nodes (optional for judge)
        while (head) { Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

