import sys

def delete_all(head, X):
    cur = head
    while cur:
        nxt = cur[1]
        if cur[0] == X:
            if cur is head:
                head = cur[1]
                if head:
                    head[2] = None
            else:
                prev = cur[2]
                prev[1] = cur[1]
                if cur[1]:
                    cur[1][2] = prev
        cur = nxt
    return head

def build_list(values):
    head = tail = None
    for v in values:
        node = [v, None, None]  # [data, next, prev]
        if head is None:
            head = tail = node
        else:
            tail[1] = node
            node[2] = tail
            tail = node
    return head

def list_to_str(head):
    if not head:
        return "-1"
    parts = []
    cur = head
    while cur:
        parts.append(str(cur[0]))
        cur = cur[1]
    return ' '.join(parts)

it = iter(sys.stdin.read().strip().split())
